const threshold = 240; // minutos
const stuck_emails = [];
const now = new Date(); // Fecha y hora actual
const limitDate = new Date(now.getTime() - threshold * 60000); // Restamos milisegundos

// En n8n, 'items' es el array de entrada que recibes del nodo anterior
for (const item of items) {
    try {
        const emailData = item.json;
        const envelope = emailData.envelope || {};
        const dateStr = envelope.date;

        if (dateStr) {
            // JavaScript Date maneja bien el formato ISO (incluyendo la 'Z')
            const emailDate = new Date(dateStr);

            // Validamos que la fecha sea válida
            if (!isNaN(emailDate.getTime())) {

                // COMPARACIÓN: ¿Es el email más viejo que el límite?
                if (emailDate < limitDate) {
                    // Calculamos la diferencia en minutos
                    const diffMs = now - emailDate;
                    const minutesStuck = Math.floor(diffMs / (1000 * 60));

                    stuck_emails.push({
                        "received_at": dateStr,
                        "minutes_stuck": minutesStuck,
                        "id": emailData.id // Guardamos ID para referencias
                    });
                }
            }
        }
    } catch (e) {
        // En n8n Code Node, 'continue' funciona dentro de un for...of
        continue;
    }
}

const hayAlerta = stuck_emails.length > 0;

const outputJson = {
    "alerta": hayAlerta,
    "cantidad_atascados": stuck_emails.length,
    "detalle_atascados": stuck_emails
};

// n8n espera que devolvamos un array de objetos con la propiedad 'json'
return [{ json: outputJson }];

const threshold = 240; // minutos
const now = new Date();
const limitDate = new Date(now.getTime() - threshold * 60000);

const stuck_files = [];

// En JavaScript/n8n recorremos el array 'items' directamente
for (const item of items) {
  try {
    // No hace falta to_py(), accedemos directamente a item.json
    const fileData = item.json;
    const dateStr = fileData.modifyTime;
    const name = fileData.name;

    if (dateStr) {
      // JavaScript reconoce formatos ISO (con Z o sin ella) automáticamente
      const fileDate = new Date(dateStr);

      // Validamos que la fecha sea correcta
      if (!isNaN(fileDate.getTime())) {

        // COMPARACIÓN: ¿El archivo es más viejo que el límite?
        if (fileDate < limitDate) {
          const diffMs = now - fileDate;
          const minsStuck = Math.floor(diffMs / (1000 * 60));

          stuck_files.push({
            "filename": name,
            "minutes_stuck": minsStuck
          });
        }
      }
    }
  } catch (e) {
    // Si hay error en un elemento, pasamos al siguiente
    continue;
  }
}

const hayAlertaFtp = stuck_files.length > 0;

const outputJson = {
  "alerta_ftp": hayAlertaFtp,
  "cantidad_archivos": stuck_files.length,
  "detalle_archivos": stuck_files
};

// Retornamos el formato estándar de n8n
return [{ json: outputJson }];

// --- CONFIGURACIÓN ---
const MAX_SKIPS = 3; 

// --- 1. OBTENER DATOS DE CONTEXTO (Loop) ---
// Identificamos en qué vuelta del bucle estamos.
// Usamos el nodo "Loop" para sacar el país actual (ARG, PER, ECU)
const loopItem = $node["Loop"].json; 
const currentContextKey = loopItem.country || 'UNKNOWN'; // Esta será la clave del "cajón"

// Obtener datos de los nodos anteriores
const mailData = $('Detect Stuck Emails').first().json || {};
const ftpData = $('Detect Stuck Files').first().json || {};

// Accedemos a la memoria global
const staticData = $getWorkflowStaticData('global');

// INICIALIZAR EL "ARCHIVADOR"
// Si no existe el objeto 'history', lo creamos.
if (!staticData.history) {
    staticData.history = {};
}

// --- 2. RECUPERAR MEMORIA ESPECÍFICA DE ESTE PAÍS ---
// Buscamos si ya hay datos guardados para ESTE país específico
// Si no hay, inicializamos en cero/vacío.
const countryMemory = staticData.history[currentContextKey] || { 
    lastSignature: "", 
    skipCount: 0 
};

// --- DEBUG: RAYOS X ---
const memoria_previa = { ...countryMemory }; // Copia para ver en el output

// --- 3. EXTRAER ESTADO ACTUAL ---
const isMailStuck = mailData.alerta === true;
const isFtpStuck = ftpData.alerta_ftp === true;

// Generamos las firmas (IDs)
const mailIds = (mailData.detalle_atascados || []).map(m => m.id).sort().join(',');
const ftpIds = (ftpData.detalle_archivos || []).map(f => f.filename).sort().join(',');

// Firma única del problema actual
const currentErrorSignature = `MAIL:[${mailIds}]__FTP:[${ftpIds}]`;

// --- 4. LÓGICA DE MEMORIA (Smart Filter Por País) ---
let lastErrorSignature = countryMemory.lastSignature;
let skipCount = countryMemory.skipCount;

let disparar_alerta = false;
let motivo = "";

if (!isMailStuck && !isFtpStuck) {
    // CASO A: Todo limpio
    lastErrorSignature = "";
    skipCount = 0;
    disparar_alerta = false;
    motivo = "Sistema OK (Sin errores)";

} else {
    // HAY ERRORES
    if (currentErrorSignature !== lastErrorSignature) {
        // CASO B: Error Nuevo
        disparar_alerta = true;
        skipCount = 0;
        motivo = "Nuevo Error Detectado";
    } else {
        // CASO C: Mismo Error
        skipCount++;

        if (skipCount >= MAX_SKIPS) {
            // CASO D: Recordatorio
            disparar_alerta = true;
            skipCount = 0; 
            motivo = `🔔 Recordatorio (Intento ${MAX_SKIPS} alcanzado)`;
        } else {
            // CASO E: Silencio
            disparar_alerta = false;
            motivo = `Silenciado por contador (${skipCount}/${MAX_SKIPS})`;
        }
    }

    // Actualizamos las variables locales
    lastErrorSignature = currentErrorSignature;
}

// --- 5. GUARDAR EN MEMORIA GLOBAL ---
// Guardamos el estado actualizado DE ESTE PAÍS en el objeto principal
staticData.history[currentContextKey] = {
    lastSignature: lastErrorSignature,
    skipCount: skipCount
};

// --- 6. CONSTRUCCIÓN DEL MENSAJE (HTML para Teams) ---
let mensaje_teams = "";
// Incluimos el PAÍS en el título para saber cuál falló
const tituloPrincipal = `<h2>Revision de entorno (${currentContextKey}): Lectura de MAIL y FTP KN</h2>`;

if (disparar_alerta) {
    let titulo = "";
    let cuerpo = [];

    if (isMailStuck && isFtpStuck) {
        titulo = "⚠️ ALERTA: Fallo General (Mail + FTP)";
    } else if (isMailStuck) {
        titulo = "📧 ALERTA: Correos en INBOX";
    } else {
        titulo = "📂 ALERTA: Archivos en FTP";
    }

    if (isMailStuck) {
        const mailCount = mailData.cantidad_atascados || 0;
        cuerpo.push(`<strong>Mail:</strong> ${mailCount} correos trabados hace +4 horas.`);
    }

    if (isFtpStuck) {
        const ftpCount = ftpData.cantidad_archivos || 0;
        cuerpo.push(`<strong>FTP:</strong> ${ftpCount} archivos sin procesar hace +4 horas.`);
    }

    mensaje_teams = `${tituloPrincipal}<br><h2>${titulo}</h2><br>${cuerpo.join('<br><br>')}<br><br><em>(Estado: ${motivo})</em>`;
}

return [{
    json: {
        pais: currentContextKey, // Dato útil para ver en el output
        enviar_notificacion: disparar_alerta,
        mensaje: mensaje_teams,
        debug_motivo: motivo,
        debug_contador: skipCount,
        debug_memoria_anterior: memoria_previa
    }
}];

